import yaml from"js-yaml";import CacheDB from"@chenyfan/cache-db";import FetchEngine from"../utils/engine.js";import pkgjson from"../../package.json";const router_cgi=async request=>{const db=new CacheDB,urlStr=request.url.toString(),urlObj=new URL(urlStr),pathname=urlObj.pathname,q=e=>urlObj.searchParams.get(e);let config;switch(pathname.split("/")[2]){case"hello":return new Response("Hello ClientWorker!");case"info":return new Response(JSON.stringify({version:pkgjson.version}),{headers:{"Content-Type":"application/json"}});case"page":return"install"!==q("type")?new Response("Error, page type not found"):fetch("/404");case"api":switch(q("type")){case"config":return fetch(q("url")||"/config.yaml").then(e=>e.text()).then(e=>yaml.load(e)).then(async e=>(await db.write("config",JSON.stringify(e),{type:"json"}),new Response("ok"))).catch(async e=>(await db.write("config",""),new Response(e)));case"clear":return caches.open("ClientWorker_ResponseCache").then(async n=>n.keys().then(async e=>(await Promise.all(e.map(e=>{n.delete(e)})),new Response("ok"))));case"hotpatch":if(config=JSON.parse(await db.read("config")),"object"!=typeof config.hotpatch)return new Response("Error, config.hotpatch not found");const hotpatch=config.hotpatch;return await FetchEngine.parallel(hotpatch).then(e=>e.text()).then(async script=>{await db.write("hotpatch",script,{type:"text"}),eval(script)}),new Response("ok");case"hotconfig":if(config=JSON.parse(await db.read("config")),"object"!=typeof config.hotconfig)return new Response("Error, config.hotconfig not found");const hotconfig=config.hotconfig,nConfig=await FetchEngine.parallel(hotconfig).then(e=>e.text()).then(e=>yaml.load(e)).then(e=>JSON.stringify(e)).catch(e=>"");return nConfig&&await db.write("config",nConfig),new Response("ok");default:return new Response("Error, api type not found")}default:return new Response("Not Found!, Client Worker!")}};export default router_cgi;